/**
 * POST/GET /api/cron/auto-article
 *
 * Cron endpoint: produce ONE auto-generated article draft by paraphrasing
 * a single existing published article that matches the chosen TargetKeyword.
 * Protected by `Authorization: Bearer ${CRON_SECRET}`.
 *
 * Spec (per editor request 2026-04-27):
 *   - 1 keyword → 1 source article → 1 paraphrased draft. Strictly 1:1.
 *   - The source MUST be a human-written published article whose topic
 *     matches the keyword. If none exists for the chosen keyword, skip.
 *   - The draft body is a faithful paraphrase of the source — same facts,
 *     same structure, but reworded. No invented claims.
 *   - The featured image (and category) from the source carry over so the
 *     draft looks complete.
 *   - The draft is flagged `isAutoGenerated=true` so editors can filter
 *     auto vs manual content in /panel/artikel.
 *
 * Flow:
 *   1. Check `SystemSetting.auto_article_enabled === "true"` — else skip
 *   2. Pick random active keyword (priority desc, random from top 10)
 *   3. Find ONE matching source article (with featuredImage, recent first)
 *   4. Call `callAI({feature: "article_draft", ...})` with paraphrase prompt
 *   5. Parse JSON; carry featuredImage + category from source
 *   6. Create Article status=DRAFT, isAutoGenerated=true, sourceArticleId set
 *   7. Update keyword.lastGeneratedAt + audit log
 *
 * All errors are trapped: endpoint always returns HTTP 200 with
 * `{success:false, error}` on failure so cron doesn't retry-spam.
 *
 * Recommend invocation: every 1 hour.
 */

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { callAI } from "@/lib/ai-client";
import { slugify } from "@/lib/utils";
import { sanitizeHtml } from "@/lib/sanitize";
import { verifyCronSecret, errorResponse } from "@/lib/api-utils";

export const dynamic = "force-dynamic";
export const maxDuration = 300;

interface GeneratedArticle {
  title: string;
  excerpt: string;
  content: string;
  suggestedTags?: string[];
}

interface SourceArticle {
  id: string;
  slug: string;
  title: string;
  excerpt: string | null;
  content: string;          // already stripped to plain text + truncated
  rawContent: string;       // original HTML (for image extraction if needed)
  featuredImage: string | null;
  publishedAt: Date | null;
  categoryId: string;
  category: { name: string } | null;
}

/**
 * Find ONE published article whose topic matches the keyword.
 *
 * Matching strategy: title match preferred (signals topic), then excerpt,
 * then content. Recency tiebreak. We also prefer articles with a
 * featuredImage so the resulting draft looks complete out of the box.
 *
 * Returns null if nothing matches — the cron skips this run.
 */
async function findSingleSource(keyword: string): Promise<SourceArticle | null> {
  const MAX_CONTEXT_CHARS = 4_500; // roughly 700 words — enough to paraphrase faithfully
  const baseWhere = {
    status: "PUBLISHED" as const,
    isAutoGenerated: false, // never paraphrase another auto-article
  };

  // Try, in order: title match (with image) → title match → excerpt match → content match.
  // First hit wins. This biases toward articles whose primary topic IS the keyword.
  const orderedQueries = [
    {
      ...baseWhere,
      title: { contains: keyword, mode: "insensitive" as const },
      featuredImage: { not: null },
    },
    {
      ...baseWhere,
      title: { contains: keyword, mode: "insensitive" as const },
    },
    {
      ...baseWhere,
      excerpt: { contains: keyword, mode: "insensitive" as const },
      featuredImage: { not: null },
    },
    {
      ...baseWhere,
      excerpt: { contains: keyword, mode: "insensitive" as const },
    },
    {
      ...baseWhere,
      content: { contains: keyword, mode: "insensitive" as const },
      featuredImage: { not: null },
    },
    {
      ...baseWhere,
      content: { contains: keyword, mode: "insensitive" as const },
    },
  ];

  for (const where of orderedQueries) {
    const article = await prisma.article.findFirst({
      where,
      orderBy: [{ publishedAt: "desc" }, { viewCount: "desc" }],
      select: {
        id: true,
        slug: true,
        title: true,
        excerpt: true,
        content: true,
        featuredImage: true,
        publishedAt: true,
        categoryId: true,
        category: { select: { name: true } },
      },
    });
    if (article) {
      return {
        ...article,
        rawContent: article.content,
        content: stripHtml(article.content).slice(0, MAX_CONTEXT_CHARS),
      };
    }
  }
  return null;
}

function stripHtml(html: string): string {
  return html
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/\s+/g, " ")
    .trim();
}

function stripCodeFence(raw: string): string {
  const trimmed = raw.trim();
  // Remove leading ```json / ```
  const fenced = trimmed.match(/^```(?:json)?\s*\n?([\s\S]*?)\n?```$/);
  if (fenced) return fenced[1].trim();
  return trimmed;
}

function tryParseJson(raw: string): GeneratedArticle | null {
  try {
    const cleaned = stripCodeFence(raw);
    const parsed = JSON.parse(cleaned);
    if (
      parsed &&
      typeof parsed === "object" &&
      typeof parsed.title === "string" &&
      typeof parsed.content === "string"
    ) {
      return {
        title: parsed.title.trim(),
        excerpt:
          typeof parsed.excerpt === "string" ? parsed.excerpt.trim() : "",
        content: parsed.content.trim(),
        suggestedTags: Array.isArray(parsed.suggestedTags)
          ? parsed.suggestedTags
              .filter((t: unknown): t is string => typeof t === "string")
              .slice(0, 10)
          : [],
      };
    }
  } catch {
    // fall through
  }
  return null;
}

function fallbackParse(raw: string, keyword: string): GeneratedArticle {
  // Pull first non-empty line as title, rest as content.
  const lines = raw
    .split(/\r?\n/)
    .map((l) => l.trim())
    .filter(Boolean);
  const title = lines[0]
    ? lines[0].replace(/^#+\s*/, "").slice(0, 120)
    : `Kabar Terkini: ${keyword}`;
  const body = lines.slice(1).join("\n\n") || raw.trim();
  const contentHtml = body
    .split(/\n{2,}/)
    .map((p) => `<p>${p.trim()}</p>`)
    .join("\n");
  return {
    title,
    excerpt: body.slice(0, 180).replace(/\s+\S*$/, ""),
    content: contentHtml || `<p>${raw.slice(0, 800)}</p>`,
    suggestedTags: [],
  };
}

async function uniqueSlug(base: string): Promise<string> {
  const root = slugify(base).slice(0, 90) || "artikel";
  const existing = await prisma.article.findUnique({
    where: { slug: root },
    select: { id: true },
  });
  if (!existing) return root;
  const suffix = Math.random().toString(36).slice(2, 8);
  return `${root}-${suffix}`;
}

async function handler(req: NextRequest) {
  const started = Date.now();
  try {
    try { verifyCronSecret(req); } catch (e) { return errorResponse(e); }

    // 1. Toggle check
    let enabled = false;
    try {
      const setting = await prisma.systemSetting.findUnique({
        where: { key: "auto_article_enabled" },
      });
      enabled = setting?.value === "true";
    } catch {
      // DB unavailable — treat as disabled
      enabled = false;
    }
    if (!enabled) {
      return NextResponse.json(
        {
          success: true,
          skipped: "disabled",
          durationMs: Date.now() - started,
        },
        { status: 200 },
      );
    }

    // 2. Pick keyword
    const keywords = await prisma.targetKeyword.findMany({
      where: { isActive: true },
      orderBy: { priority: "desc" },
      take: 10,
    });
    if (keywords.length === 0) {
      return NextResponse.json(
        {
          success: true,
          skipped: "no-active-keywords",
          durationMs: Date.now() - started,
        },
        { status: 200 },
      );
    }
    const kw = keywords[Math.floor(Math.random() * keywords.length)];

    // 3. Find ONE source article whose topic matches the keyword.
    //    Strict 1:1 — if no source exists, skip (the cron should not invent
    //    facts about a topic we have no human-written reference for).
    const source = await findSingleSource(kw.keyword);
    if (!source) {
      return NextResponse.json(
        {
          success: true,
          skipped: "no-source-article-for-keyword",
          keyword: kw.keyword,
          durationMs: Date.now() - started,
        },
        { status: 200 },
      );
    }

    const sourceDate = source.publishedAt
      ? new Date(source.publishedAt).toLocaleDateString("id-ID", {
          day: "numeric",
          month: "long",
          year: "numeric",
        })
      : "";

    const userPrompt = `Tugas: tulis ulang (PARAFRASA) artikel berita berikut dalam Bahasa Indonesia jurnalistik. Bukan tulis baru, bukan sintesis — paraphrase artikel ini.

ARTIKEL SUMBER (judul / kategori / tanggal / isi):
JUDUL: ${source.title}
KATEGORI: ${source.category?.name ?? "Umum"}
TANGGAL: ${sourceDate}
${source.excerpt ? `RINGKASAN: ${source.excerpt}\n` : ""}ISI:
${source.content}

ATURAN PARAFRASA (WAJIB):
1. Pertahankan SEMUA fakta dari sumber — nama, jabatan, angka, tanggal, lokasi, kutipan langsung jangan diubah.
2. Reword setiap kalimat dengan struktur kata baru. Jangan menyalin kalimat persis.
3. Jangan menambah klaim baru, prediksi, atau fakta yang tidak ada di sumber.
4. Jangan menghapus poin penting. Pertahankan urutan kronologis / argumentasi sumber.
5. Panjang artikel paraphrase: ~80–110% panjang sumber. Body 400–800 kata, sesuai sumber.
6. Gaya bahasa: lead 5W+1H di paragraf pertama, gunakan paragraf pendek 2–4 kalimat, sertakan minimal 1 sub-heading <h2> kalau sumber punya struktur sectioned.
7. Judul baru: ringkasan inti, 50–80 karakter, BEDA dari judul sumber tapi tetap akurat menggambarkan topik.
8. Excerpt: 150–200 karakter, tarik fakta paling kuat dari paragraf pertama.

Keyword fokus: "${kw.keyword}"

Format output WAJIB JSON valid (tanpa teks lain, tanpa code-fence):
{
  "title": "judul paraphrase 50-80 karakter",
  "excerpt": "ringkasan 150-200 karakter",
  "content": "body HTML dengan <p>, <h2>, <blockquote> kalau sumber punya kutipan, <ul> kalau ada list",
  "suggestedTags": ["tag1", "tag2", "tag3"]
}`;

    let aiResult;
    try {
      aiResult = await callAI({
        feature: "article_draft",
        userPrompt,
        maxTokens: 2000,
        temperature: 0.7,
      });
    } catch (e) {
      return NextResponse.json(
        {
          success: false,
          error: `AI call failed: ${e instanceof Error ? e.message : String(e)}`,
          keyword: kw.keyword,
          durationMs: Date.now() - started,
        },
        { status: 200 },
      );
    }

    // 4. Parse
    const parsed =
      tryParseJson(aiResult.text) ?? fallbackParse(aiResult.text, kw.keyword);

    // 5. Resolve author + category
    const admin = await prisma.user.findFirst({
      where: { role: "SUPER_ADMIN" },
      orderBy: { createdAt: "asc" },
      select: { id: true },
    });
    if (!admin) {
      return NextResponse.json(
        {
          success: false,
          error: "No SUPER_ADMIN user exists to own the draft",
          keyword: kw.keyword,
          durationMs: Date.now() - started,
        },
        { status: 200 },
      );
    }

    // Category & featured image inherit from source — paraphrase shouldn't
    // drift the topic, and the visual continues to make sense.
    const categoryId = source.categoryId;
    const featuredImage = source.featuredImage;

    // 6. Create article — sourceArticleId always set (we abort earlier if no source).
    const slug = await uniqueSlug(parsed.title);
    let article;
    try {
      article = await prisma.article.create({
        data: {
          title: parsed.title.slice(0, 250),
          slug,
          content: sanitizeHtml(parsed.content),
          excerpt: parsed.excerpt.slice(0, 500) || null,
          featuredImage,
          status: "DRAFT",
          isAutoGenerated: true,
          sourceArticleId: source.id,
          authorId: admin.id,
          categoryId,
        },
        select: { id: true, slug: true, title: true },
      });
    } catch (e) {
      return NextResponse.json(
        {
          success: false,
          error: `DB create failed: ${e instanceof Error ? e.message : String(e)}`,
          keyword: kw.keyword,
          durationMs: Date.now() - started,
        },
        { status: 200 },
      );
    }

    // 7. Update keyword.lastGeneratedAt (best-effort)
    try {
      await prisma.targetKeyword.update({
        where: { id: kw.id },
        data: { lastGeneratedAt: new Date() },
      });
    } catch {
      // swallow
    }

    // Audit log (best-effort)
    try {
      await prisma.auditLog.create({
        data: {
          userId: admin.id,
          action: "CRON_AUTO_ARTICLE",
          entity: "article",
          entityId: article.id,
          detail: JSON.stringify({
            keyword: kw.keyword,
            provider: aiResult.provider,
            tokens: aiResult.totalTokens,
            sourceId: source.id,
            sourceSlug: source.slug,
            mode: "paraphrase",
          }),
        },
      });
    } catch {
      // swallow
    }

    return NextResponse.json(
      {
        success: true,
        articleId: article.id,
        slug: article.slug,
        titleGenerated: article.title,
        keyword: kw.keyword,
        provider: aiResult.provider,
        tokens: aiResult.totalTokens,
        mode: "paraphrase",
        source: {
          id: source.id,
          slug: source.slug,
          title: source.title,
          hadFeaturedImage: Boolean(featuredImage),
        },
        durationMs: Date.now() - started,
      },
      { status: 200 },
    );
  } catch (e) {
    return NextResponse.json(
      {
        success: false,
        error: e instanceof Error ? e.message : String(e),
        durationMs: Date.now() - started,
      },
      { status: 200 },
    );
  }
}

export async function GET(req: NextRequest) {
  return handler(req);
}

export async function POST(req: NextRequest) {
  return handler(req);
}
